// Reusable functions
function getGreetingByTime() {
  const hour = new Date().getHours();
  if (hour < 12) return "Good Morning";
  if (hour < 17) return "Good Afternoon";
  return "Good Evening";
}

function updateUserGreeting(root_element) {
  const title = root_element.querySelector('.welcome_title');
  if (!title) return;
  const name = frappe.session.user_fullname || frappe.session.user.split('@')[0];
  title.textContent = `${getGreetingByTime()} ${name} !`;
}

function setUserProfileImage(root_element) {
  if (!frappe?.session) return;
  const img = root_element.querySelector('#user-profile-img');
  if (!img) return;
  const user = frappe.session.user;

  frappe.db.get_value("Employee", { user_id: user }, "image")
    .then(r => {
      let image = r.message?.image;
      if (!image && frappe.session.user_image) {
        image = frappe.session.user_image;
      }
      img.src = image || "/assets/frappe/images/default-avatar.png";
    })
    .catch(err => console.log("Error fetching employee image:", err));
}

// Workspace-safe execution (runs after desk loads)
frappe.after_ajax(() => {
  if (typeof root_element !== "undefined") {
    updateUserGreeting(root_element);
    setUserProfileImage(root_element);
  }
});


(function () {
  console.log("Welcome block JS loaded");


  function init(root) {
    if (!root) return;

    console.log("Init welcome block");

    const title = root.querySelector(".welcome_title");
    if (title) {
      const name =
        frappe.session.user_fullname ||
        frappe.session.user.split("@")[0];
      title.textContent = `${getGreetingByTime()} ${name}!`;
    }

    const btnIn = root.querySelector("#btn-checkin");
    const btnOut = root.querySelector("#btn-checkout");

    btnIn?.addEventListener("click", () => {
      console.log("Check IN clicked");
      createCheckin("IN");
    });

    btnOut?.addEventListener("click", () => {
      console.log("Check OUT clicked");
      createCheckin("OUT");
    });
  }
function createCheckin(log_type) {
  if (!navigator.geolocation) {
    frappe.msgprint("Geolocation is not supported by this browser");
    return;
  }

  frappe.show_alert({
    message: "Fetching location…",
    indicator: "blue"
  });

  navigator.geolocation.getCurrentPosition(
    (position) => {
      const latitude = position.coords.latitude;
      const longitude = position.coords.longitude;

      console.log("Location:", latitude, longitude);

      frappe.call({
        method:
          "hrms.hr.doctype.employee_checkin.employee_checkin.add_log_based_on_employee_field",
        args: {
          employee_fieldname: "user_id",
          employee_field_value: frappe.session.user,
          timestamp: frappe.datetime.now_datetime(),
          log_type: log_type,
          device_id: "Web Workspace",

          // ✅ REQUIRED when geolocation is enabled
          latitude: latitude,
          longitude: longitude
        },
        callback(r) {
          frappe.show_alert({
            message: `Checked ${log_type} successfully`,
            indicator: "green"
          });
        },
        error(err) {
          console.error(err);
          frappe.msgprint({
            title: "Check-in Failed",
            message: err.message || "Location validation failed",
            indicator: "red"
          });
        }
      });
    },
    (error) => {
      frappe.msgprint({
        title: "Location Error",
        message: "Please allow location access to check in",
        indicator: "red"
      });
    },
    {
      enableHighAccuracy: true,
      timeout: 10000,
      maximumAge: 0
    }
  );
}

// Workspace provides root_element
  init(root_element);
})();

