/* ──────────────────────────────────────────────
   Welcome Card – Premium Style
─────────────────────────────────────────────── */

.welcome-card {
  background: linear-gradient(
    135deg,
    #ecf4e9 0%,   /* very light green */
    #f3f8f1 50%,
    #ffffff 100%
  );
  border: 1px solid #bbf7d0;
  border-radius: 18px;
  box-shadow: 0 12px 28px -12px rgba(16, 185, 129, 0.25);
}


.welcome-card:hover {
  transform: translateY(-2px);
  box-shadow:
    0 28px 45px -22px rgba(15, 23, 42, 0.35);
}

/* Avatar */
.welcome-avatar {
  width: 92px;
  height: 92px;
  object-fit: cover;
  border: 4px solid #fff;
  background: #fff;
  box-shadow: 0 10px 25px rgba(0,0,0,0.15);
}

/* Title */
.welcome-title {
  font-size: 2rem;
  font-weight: 700;
  color: #0f172a;
  letter-spacing: -0.03em;
  margin-bottom: 0.5rem;
}

/* Subtitle */
.welcome-subtitle {
  font-size: 1.05rem;
  color: #64748b;
  line-height: 1.6;
  max-width: 520px;
}

/* Actions */
.welcome-actions {
  display: flex;
  gap: 14px;
  flex-wrap: wrap;
}
/* Check In – Indigo */
/* Check In – Light Blue */
.btn-checkin {
  background: #00b300;
  color: #ffffff;
}

.btn-checkin:hover {
  background: #00b300;
  box-shadow: 0 8px 22px -8px rgba(14, 165, 233, 0.5);
}

/* Check Out – Muted Blue-Gray */
.btn-checkout {
  background:  #b30000;
  color: #ffffff;
}

.btn-checkout:hover {
  background:  #b30000;
  box-shadow: 0 8px 22px -8px rgba(56, 189, 248, 0.45);
}

/* Status Message */
#status-msg {
  border-radius: 12px;
  font-weight: 500;
  padding: 0.9rem 1.2rem;
}

/* Responsive */
@media (max-width: 768px) {
  .welcome-title {
    font-size: 1.7rem;
  }

  .welcome-actions {
    flex-direction: column;
  }

  .welcome-actions button {
    width: 100%;
  }
}
